import React from "react";
import { Link } from "react-router-dom";

export default function Navbar() {
  return (
    <nav style={{ padding: "10px", backgroundColor: "#ff5a5f" }}>
      <Link to="/" style={{ marginRight: "10px", color: "#fff", textDecoration: "none" }}>Home</Link>
      <Link to="/experience" style={{ marginRight: "10px", color: "#fff", textDecoration: "none" }}>Experience</Link>
      <Link to="/services" style={{ marginRight: "10px", color: "#fff", textDecoration: "none" }}>Services</Link>
      <Link to="/login" style={{ marginRight: "10px", color: "#fff", textDecoration: "none" }}>Login</Link>
      <Link to="/signup" style={{ color: "#fff", textDecoration: "none" }}>Signup</Link>
    </nav>
  );
}
